; ***************************************************************************************
; Claim Tube if present
; 
; Claim the Tube for a data transfer if a Tube is present.
; Copies the 4-byte transfer address from the control block
; to workspace and sets the Tube-in-use flag.
; 
; &8027 referenced 3 times by &8111, &8b61, &bb67
.claim_tube
    ldy #4                                                            ; 8027: a0 04       ..             ; Y=4: copy 4 bytes
    bit zp_adfs_flags                                                 ; 8029: 24 cd       $.             ; Is Tube present?
    bpl return_1                                                      ; 802b: 10 15       ..             ; No, return immediately
; &802d referenced 1 time by &8033
.copy_tube_addr_loop
    lda (zp_ctrl_blk_lo),y                                            ; 802d: b1 b0       ..             ; Copy 4-byte transfer address
    sta wksp_tube_transfer_addr,y                                     ; 802f: 99 26 10    .&.            ; Store in Tube transfer workspace
    dey                                                               ; 8032: 88          .              ; Next byte
    bne copy_tube_addr_loop                                           ; 8033: d0 f8       ..             ; Loop for 4 bytes
    lda zp_adfs_flags                                                 ; 8035: a5 cd       ..             ; Set bit 6: Tube in use
    ora #&40 ; '@'                                                    ; 8037: 09 40       .@             ; Set Tube-in-use flag
    sta zp_adfs_flags                                                 ; 8039: 85 cd       ..             ; Store updated flags
; &803b referenced 4 times by &8040, &a438, &b839, &b9a3
.claim_tube_retry
