    jsr reload_fsm_and_dir_then_brk                                   ; a00a: 20 48 83     H.            ; Reload FSM and directory then raise error
    equb &cb                                                          ; a00d: cb          .              ; Error &CB: Bad opt
    equs "Bad opt", 0                                                 ; a00e: 42 61 64... Bad

