    asl a                                                             ; a35e: 0a          .              ; Second shift
    asl a                                                             ; a35f: 0a          .              ; Third shift
    asl a                                                             ; a360: 0a          .              ; Fourth shift
    ora wksp_disc_op_mem_addr,x                                       ; a361: 1d 16 10    ...            ; OR in low nibble
    rts                                                               ; a364: 60          `              ; Return combined byte

